// pricing.ts - simplified per-account pricing resolution
interface PricingTier {
  accountId: string;
  discountPercent: number;
  volumeBreaks: { minQty: number; discountPercent: number }[];
}

function resolvePrice(
  basePrice: number,
  quantity: number,
  tier: PricingTier
): number {
  const applicableBreak = tier.volumeBreaks
    .filter((b) => quantity >= b.minQty)
    .sort((a, b) => b.minQty - a.minQty)[0];

  const discount = applicableBreak
    ? applicableBreak.discountPercent
    : tier.discountPercent;

  return Number((basePrice * (1 - discount / 100)).toFixed(2));
}

// Example: account with a 10 percent base discount,
// plus 15 percent once they order 100 or more units
const tier: PricingTier = {
  accountId: 'acct_4471',
  discountPercent: 10,
  volumeBreaks: [{ minQty: 100, discountPercent: 15 }],
};

resolvePrice(24.0, 120, tier); // returns 20.4
